        attempt (pstring "\"version\" \":\" quoted_string" >>% MetadataItemNode.U0022versionU0022U0022ColonU0022quotedUnderstring)
        attempt (pstring "tags\" \":\" \"[\" tag_list \"]" >>% MetadataItemNode.TagsU0022U0022ColonU0022U0022U005BU0022tagUnderlistU0022U005D)
        attempt (pstring "\"description\" \":\" quoted_string" >>% MetadataItemNode.U0022descriptionU0022U0022ColonU0022quotedUnderstring) ]

do metadataItemRefImpl.Value <- metadataItemParser

let private tagListParser : Parser<TagListNode, unit> =
    pstring "quoted_string { \",\" quoted_string }" |>> TagListNode.TagList

do tagListRefImpl.Value <- tagListParser

let private conditionalExerciseParser : Parser<ConditionalExerciseNode, unit> =
    pstring "\"if\" condition \"then\" exercise [ \"else\" exercise ]" |>> ConditionalExerciseNode.ConditionalExercise

do conditionalExerciseRefImpl.Value <- conditionalExerciseParser

let private conditionParser : Parser<ConditionNode, unit> =
    choice [
        attempt (skillConditionRef |>> ConditionNode.SkillCondition)
        attempt (progressConditionRef |>> ConditionNode.ProgressCondition)
        attempt (timeConditionRef |>> ConditionNode.TimeCondition) ]

do conditionRefImpl.Value <- conditionParser

let private skillConditionParser : Parser<SkillConditionNode, unit> =
    pstring "\"skill_level\" comparison_op skill_level" |>> SkillConditionNode.SkillCondition

do skillConditionRefImpl.Value <- skillConditionParser

let private progressConditionParser : Parser<ProgressConditionNode, unit> =
    pstring "progress\" comparison_op integer \"%" |>> ProgressConditionNode.ProgressCondition

do progressConditionRefImpl.Value <- progressConditionParser

let private timeConditionParser : Parser<TimeConditionNode, unit> =
    pstring "session_time\" comparison_op integer \"minutes" |>> TimeConditionNode.TimeCondition

do timeConditionRefImpl.Value <- timeConditionParser

let private comparisonOpParser : Parser<ComparisonOpNode, unit> =
    choice [
        attempt (pstring ">" >>% ComparisonOpNode.Gt)
        attempt (pstring "<" >>% ComparisonOpNode.Lt)
        attempt (pstring ">=" >>% ComparisonOpNode.GtEq)
        attempt (pstring "<=" >>% ComparisonOpNode.LtEq)
        attempt (pstring "==" >>% ComparisonOpNode.EqEq)
        attempt (pstring "!=" >>% ComparisonOpNode.BangEq) ]

do comparisonOpRefImpl.Value <- comparisonOpParser

let private adaptiveExerciseParser : Parser<AdaptiveExerciseNode, unit> =
    pstring "\"adaptive\" exercise_type exercise_duration \":\" exercise_description
                   \"start_at\" difficulty_level
                   \"adjust_by\" adjustment_spec" |>> AdaptiveExerciseNode.AdaptiveExercise

do adaptiveExerciseRefImpl.Value <- adaptiveExerciseParser

let private adjustmentSpecParser : Parser<AdjustmentSpecNode, unit> =
    choice [
        attempt (pstring "tempo\" \"±\" integer \"bpm" >>% AdjustmentSpecNode.TempoU0022U0022U00B1U0022integerU0022bpm)
        attempt (pstring "difficulty\" \"±\" integer \"%" >>% AdjustmentSpecNode.DifficultyU0022U0022U00B1U0022integerU0022Percent)
        attempt (pstring "duration\" \"±\" integer \"minutes" >>% AdjustmentSpecNode.DurationU0022U0022U00B1U0022integerU0022minutes) ]

do adjustmentSpecRefImpl.Value <- adjustmentSpecParser

let private practiceLoopParser : Parser<PracticeLoopNode, unit> =
    pstring "repeat\" integer \"times\" \"{\" exercise_list \"}" |>> PracticeLoopNode.PracticeLoop

do practiceLoopRefImpl.Value <- practiceLoopParser

let private practiceCycleParser : Parser<PracticeCycleNode, unit> =
    pstring "cycle\" cycle_duration \"{\" exercise_list \"}" |>> PracticeCycleNode.PracticeCycle

do practiceCycleRefImpl.Value <- practiceCycleParser

let private cycleDurationParser : Parser<CycleDurationNode, unit> =
    pstring "integer ( \"days\" | \"weeks\" | \"months\" )" |>> CycleDurationNode.CycleDuration

do cycleDurationRefImpl.Value <- cycleDurationParser

let private trackingSpecParser : Parser<TrackingSpecNode, unit> =
    pstring "track\" \"{\" tracking_list \"}" |>> TrackingSpecNode.TrackingSpec

do trackingSpecRefImpl.Value <- trackingSpecParser

let private trackingListParser : Parser<TrackingListNode, unit> =
    pstring "tracking_item { \",\" tracking_item }" |>> TrackingListNode.TrackingList

do trackingListRefImpl.Value <- trackingListParser

let private trackingItemParser : Parser<TrackingItemNode, unit> =
    choice [
        attempt (pstring "accuracy" >>% TrackingItemNode.Accuracy)
        attempt (pstring "tempo" >>% TrackingItemNode.Tempo)
        attempt (pstring "consistency" >>% TrackingItemNode.Consistency)
        attempt (pstring "mistakes" >>% TrackingItemNode.Mistakes)
        attempt (pstring "improvement_rate" >>% TrackingItemNode.ImprovementUnderrate)
        attempt (pstring "session_completion" >>% TrackingItemNode.SessionUndercompletion) ]

do trackingItemRefImpl.Value <- trackingItemParser

/// Parse PracticeRoutine from a string. Returns Ok or Error.
let parse (input: string) : Result<PracticeRoutineNode, string> =
    match run (practiceRoutineParser .>> eof) input with
    | Success (v, _, _) -> Result.Ok v
    | Failure (msg, _, _) -> Result.Error msg
